// Extract the innertube API key from the page
const html = $json.data;
const videoId = $('Extract YouTube Video ID').first().json.videoId;

// Extract API key with improved regex
const apiKeyMatch = html.match(/"INNERTUBE_API_KEY":\s*"([^"]+)"/);
if (!apiKeyMatch) {
  throw new Error('Could not find YouTube API key in page. Video may be restricted or unavailable.');
}
const apiKey = apiKeyMatch[1];

// IMPORTANT: Use ANDROID client for better caption availability
const context = {
  client: {
    clientName: "ANDROID",
    clientVersion: "20.10.38",
    androidSdkVersion: 30,
    userAgent: "com.google.android.youtube/20.10.38 (Linux; U; Android 11) gzip",
    hl: "en",
    timeZone: "UTC",
    utcOffsetMinutes: 0
  }
};

return [{
  json: {
    videoId: videoId,
    apiKey: apiKey,
    context: context,
    preferredLanguage: "en"
  }
}];

// Enhanced caption extraction with better error handling
const playerData = $json;
const preferredLanguage = $node["Extract API Info (Android Client)"].json.preferredLanguage;

// Check multiple possible locations for captions
let captionTracks = null;

// Try primary location
if (playerData.captions && playerData.captions.playerCaptionsTracklistRenderer) {
  captionTracks = playerData.captions.playerCaptionsTracklistRenderer.captionTracks;
}

// Check if video is available and has captions
if (playerData.playabilityStatus) {
  if (playerData.playabilityStatus.status === 'UNPLAYABLE') {
    throw new Error(`Video is unplayable: ${playerData.playabilityStatus.reason || 'Unknown reason'}`);
  }
  if (playerData.playabilityStatus.status === 'ERROR') {
    throw new Error(`Video error: ${playerData.playabilityStatus.reason || 'Unknown error'}`);
  }
}

if (!captionTracks || captionTracks.length === 0) {
  // Provide helpful error message
  const videoTitle = playerData.videoDetails?.title || 'Unknown video';
  const videoId = $node["Extract API Info (Android Client)"].json.videoId;

  throw new Error(
    `No captions available for video: "${videoTitle}" (ID: ${videoId}). ` +
    `This video may not have subtitles/captions enabled, or they may be restricted. ` +
    `Try a different video or check if the video has CC available on YouTube.`
  );
}

// Process available tracks
const availableTracks = captionTracks.map(track => ({
  language: track.languageCode,
  name: track.name?.simpleText || track.name?.runs?.[0]?.text || track.languageCode,
  baseUrl: track.baseUrl,
  isTranslatable: track.isTranslatable || false,
  kind: track.kind || track.vssId?.includes('.a.') ? 'automatic' : 'standard',
  vssId: track.vssId
}));

// Find the preferred language track
let selectedTrack = availableTracks.find(track => 
  track.language === preferredLanguage || 
  track.language.startsWith(preferredLanguage + '-')
);

// Fallback to English if preferred not found
if (!selectedTrack && preferredLanguage !== 'en') {
  selectedTrack = availableTracks.find(track => 
    track.language === 'en' || 
    track.language.startsWith('en-')
  );
}

// Use first available if still not found
if (!selectedTrack) {
  selectedTrack = availableTracks[0];
}

// Add format parameter for better output
// selectedTrack.baseUrl += '&fmt=json3';

return [{
  json: {
    videoId: $node["Extract API Info (Android Client)"].json.videoId,
    videoTitle: playerData.videoDetails?.title || 'Unknown',
    videoAuthor: playerData.videoDetails?.author || 'Unknown',        // ADDED
    channelId: playerData.videoDetails?.channelId || '',              // ADDED
    viewCount: playerData.videoDetails?.viewCount || '0',             // ADDED (optional)
    videoDuration: playerData.videoDetails?.lengthSeconds || 0,
    selectedTrack: selectedTrack,
    availableTracks: availableTracks,
    totalTracks: availableTracks.length,
    trackType: selectedTrack.kind
  }
}];

// Process the transcript data with XML parsing support
const transcriptData = $json;
const videoInfo = $node["Extract Caption Info (Enhanced)"].json;

// Check if we received XML data
if (typeof transcriptData === 'string' || (transcriptData.data && typeof transcriptData.data === 'string')) {
  // We have XML data
  const xmlData = transcriptData.data || transcriptData;

  // Parse XML to extract transcript text
  let fullText = '';

  // Extract all paragraph tags
  const paragraphRegex = /<p\s+t="(\d+)"(?:\s+d="(\d+)")?[^>]*>(.*?)<\/p>/gs;
  let paragraphMatch;

  while ((paragraphMatch = paragraphRegex.exec(xmlData)) !== null) {
    const content = paragraphMatch[3];

    // Skip empty paragraphs
    if (!content || content.trim() === '' || content.includes('a="1"')) {
      continue;
    }

    // Extract text from segments within the paragraph
    let paragraphText = '';
    const segmentRegex = /<s(?:\s+[^>]*)?>([^<]*)<\/s>/g;
    let segmentMatch;

    while ((segmentMatch = segmentRegex.exec(content)) !== null) {
      const segmentText = segmentMatch[1];
      if (segmentText) {
        paragraphText += segmentText;
      }
    }

    // Clean up the text
    paragraphText = paragraphText
      .replace(/&quot;/g, '"')
      .replace(/&#39;/g, "'")
      .replace(/&amp;/g, '&')
      .replace(/&lt;/g, '<')
      .replace(/&gt;/g, '>')
      .trim();

    if (paragraphText) {
      fullText += paragraphText + ' ';
    }
  }

  // Clean up full text
  fullText = fullText.trim().replace(/\s+/g, ' ');

  if (!fullText) {
    throw new Error('No transcript text could be extracted from the XML data');
  }

  return [{
    json: {
      videoId: videoInfo.videoId,
      videoTitle: videoInfo.videoTitle || 'Unknown',
      videoAuthor: videoInfo.videoAuthor || 'Unknown',
      channelId: videoInfo.channelId || '',
      viewCount: videoInfo.viewCount || '0',
      language: videoInfo.selectedTrack.language,
      languageName: videoInfo.selectedTrack.name,
      transcriptType: videoInfo.trackType,
      fullText: fullText,
      metadata: {
        videoUrl: `https://www.youtube.com/watch?v=${videoInfo.videoId}`,
        channelUrl: videoInfo.channelId ? `https://www.youtube.com/channel/${videoInfo.channelId}` : '',
        fetchedAt: new Date().toISOString(),
        format: 'XML'
      }
    }
  }];
} else {
  // Handle JSON format
  let events = [];
  if (transcriptData.events) {
    events = transcriptData.events;
  } else if (transcriptData.transcript) {
    events = transcriptData.transcript.events || [];
  } else if (Array.isArray(transcriptData)) {
    events = transcriptData;
  }

  if (events.length === 0) {
    throw new Error('Transcript data is empty or in unexpected format');
  }

  // Extract full text from events
  let fullText = '';

  for (const event of events) {
    // Skip non-text events
    if (!event.segs && !event.text) continue;

    if (event.segs) {
      // Handle segmented text
      let segmentText = '';
      for (const seg of event.segs) {
        if (seg.utf8) {
          segmentText += seg.utf8;
        }
      }

      if (segmentText.trim()) {
        fullText += segmentText.trim() + ' ';
      }
    } else if (event.text) {
      // Handle simple text format
      fullText += event.text.trim() + ' ';
    }
  }

  // Clean up full text
  fullText = fullText.trim().replace(/\s+/g, ' ');

  return [{
    json: {
      videoId: videoInfo.videoId,
      videoTitle: videoInfo.videoTitle || 'Unknown',
      videoAuthor: videoInfo.videoAuthor || 'Unknown',
      channelId: videoInfo.channelId || '',
      viewCount: videoInfo.viewCount || '0',
      language: videoInfo.selectedTrack.language,
      languageName: videoInfo.selectedTrack.name,
      transcriptType: videoInfo.trackType,
      fullText: fullText,
      metadata: {
        videoUrl: `https://www.youtube.com/watch?v=${videoInfo.videoId}`,
        channelUrl: videoInfo.channelId ? `https://www.youtube.com/channel/${videoInfo.channelId}` : '',
        fetchedAt: new Date().toISOString(),
        format: 'JSON'
      }
    }
  }];
}

// Get Record ID from current item
const recordId = $input.first().json.id;

// Get the transcript directly
const inputText = $('Process Transcript').first().json.fullText;

if (!inputText || inputText.length === 0) {
  throw new Error('No transcript text to chunk');
}

// Chunking configuration
const maxChunkSize = 20000;
const minChunkSize = Math.floor(maxChunkSize * 0.25);

let chunks = [];
let chunkOrder = 1;

// Add chunk with Record ID and order
function addChunk(text) {
  chunks.push({
    recordId: recordId,
    order: chunkOrder,
    text: text
  });
  chunkOrder++;
}

// Find last period in text for clean sentence breaks
function findLastPeriodIndex(text, startFromIndex) {
  for (let i = startFromIndex; i >= 0; i--) {
    if (text[i] === '.') {
      return i + 1;
    }
  }
  return -1;
}

// Main chunking logic
let startIndex = 0;
while (startIndex < inputText.length) {
  let endIndex = Math.min(startIndex + maxChunkSize, inputText.length);
  let chunkText = inputText.slice(startIndex, endIndex);

  // If not at the end, try to break at a sentence
  if (endIndex < inputText.length) {
    let lastPeriodIndex = findLastPeriodIndex(chunkText, chunkText.length - 1);
    if (lastPeriodIndex !== -1) {
      endIndex = startIndex + lastPeriodIndex;
      chunkText = inputText.slice(startIndex, endIndex);
    }

    // Avoid tiny final chunks
    let nextChunkSize = Math.min(maxChunkSize, inputText.length - endIndex);
    if (nextChunkSize < minChunkSize) {
      endIndex = Math.min(endIndex + nextChunkSize, inputText.length);
      chunkText = inputText.slice(startIndex, endIndex);
    }
  }

  addChunk(chunkText);
  startIndex = endIndex;
}

// Return each chunk as a separate item
return chunks.map(chunk => ({
  json: chunk
}));

for (const item of $input.all()) {
  const youtubeUrl = item.json['YouTube Video URL'] || '';

  let videoId = null;

  // Try each pattern until we find a match
  const patterns = [
    /[?&]v=([a-zA-Z0-9_-]{11})/,           // youtube.com/watch?v=
    /youtu\.be\/([a-zA-Z0-9_-]{11})/,      // youtu.be/
    /embed\/([a-zA-Z0-9_-]{11})/,          // youtube.com/embed/
    /shorts\/([a-zA-Z0-9_-]{11})/,         // youtube.com/shorts/
    /live\/([a-zA-Z0-9_-]{11})/,           // youtube.com/live/
  ];

  for (const pattern of patterns) {
    const match = youtubeUrl.match(pattern);
    if (match) {
      videoId = match[1];
      break;
    }
  }

  // Check if it's already just the video ID
  if (!videoId && /^[a-zA-Z0-9_-]{11}$/.test(youtubeUrl.trim())) {
    videoId = youtubeUrl.trim();
  }

  item.json.videoId = videoId;
  item.json.standardUrl = videoId ? `https://www.youtube.com/watch?v=${videoId}` : null;
}

return $input.all();

// Get the first item from Apify response
const data = $input.first().json;

// Compile transcript segments into full text
const fullTranscript = data.transcript
  .map(segment => segment.text)
  .join(' ');

// Return everything with correct fields
return {
  // Video identifiers
  videoId: data.video_id,
  url: data.url,

  // Video metadata
  title: data.title,
  description: data.description,
  thumbnail: data.thumbnail,
  publishedAt: data.published_at,
  duration: data.duration_seconds,

  // Engagement stats
  viewCount: data.view_count,
  likeCount: data.like_count,
  commentCount: data.comment_count,

  // Channel info
  channelId: data.channel_id,
  channelName: data.channel_name,
  subscriberCount: data.subscriber_count,

  // Transcript data
  language: data.language,
  isAutoGenerated: data.is_auto_generated,
  transcript: fullTranscript
};

